if (Array.isArray(links) && links.length > 0) {
  const linkItems = links
    .filter((link: { label?: string, to?: string }) => link.label && link.to)
    .map((link: { label: string, to: string }) => ['li', {}, ['a', { href: link.to }, link.label]])
  if (linkItems.length > 0) {
    page.body.value.push(['hr'] as unknown as MinimarkNode)
    page.body.value.push(['ul', {}, ...linkItems] as unknown as MinimarkNode)
  }
}

window.addEventListener('keydown', (e) => {
  if (e.metaKey || e.ctrlKey || e.altKey || e.shiftKey) {
    window.parent.postMessage({
      type: 'nuxt-content:preview:keydown',
      payload: {
        key: e.key,
        metaKey: e.metaKey,
        ctrlKey: e.ctrlKey,
        shiftKey: e.shiftKey,
        altKey: e.altKey,
      },
    }, '*')
  }
})

if (columns.length === 1) {
  if (
    columns[0] !== '*'
    && !columns[0]?.match(SQL_COUNT_REGEX)
    && !columns[0]?.match(/^"[a-z_]\w+"$/i)
  ) {
    throw new Error(`Invalid query: Column '${columns[0]}' has invalid format. Expected *, COUNT(), or a quoted column name`)
  }
}
else if (!columns.every(column => column.match(/^"[a-z_]\w+"$/i))) {
  throw new Error('Invalid query: Multiple columns must be properly quoted and alphanumeric')
}

const sourceMap = collections.flatMap((c) => {
    if (c.source) {
      return c.source.filter(s => !s.repository).map((s) => {
        const { fixed } = parseSourceBase(s)
        return { collection: c, source: s, cwd: s.cwd && withTrailingSlash(s.cwd), prefix: s.cwd && withTrailingSlash(join(s.cwd, fixed)) }
      })
    }
    return []
  }).filter(({ source }) => source.cwd)

return {
  $schema: s1.$schema,
  $ref: s1.$ref,
  definitions: Object.fromEntries(
    Object.entries(s1.definitions).map(([key, def1]) => {
      const def2 = s2.definitions[key]
      if (!def2) return [key, def1]

      return [key, {
        ...def1,
        properties: { ...def1.properties, ...def2.properties },
        required: [...new Set([...def1.required, ...(def2.required || [])])],
      }]
    }),
  ),
}

const transitionType = {
  right: {
    'enter-from-class': 'transform translate-x-1/1',
    'leave-to-class': 'transform translate-x-1/1',
  },
  top: {
    'enter-from-class': 'transform translate-y--1/1',
    'leave-to-class': 'transform translate-y--1/1',
  },
  bottom: {
    'enter-from-class': 'transform translate-y-1/1',
    'leave-to-class': 'transform translate-y-1/1',
  },
}

await rpc.writeStaticAssets([...uploadFiles], props.folder).then(() => {
  close()
  devtoolsUiShowNotification({
    message: 'Files uploaded successfully!',
    icon: 'i-carbon:checkmark',
  })
}).catch((error) => {
  close()
  devtoolsUiShowNotification({
    message: `Error uploading files: ${error?.message ?? 'unknown'}`,
    icon: 'i-carbon-warning',
    classes: 'text-red',
  })
})

const finalPath = computed(() => {
  let query = new URLSearchParams(parsedQuery.value).toString()
  if (query)
    query = `?${query}`
  const path = `/_nitro/tasks/${props.task.name}${query}`

  let base = config.value?.app.baseURL || ''
  if (base === './' || base === '.')
    base = ''
  if (base.endsWith('/'))
    base = base.slice(0, -1)
  return (base + path)
})

const tabCommands = computed(() => tabs.value
    .map((i): CommandItem => {
      return {
        id: `tab:${i.name}`,
        title: i.title || i.name,
        icon: i.icon,
        action: () => {
          if ('onClick' in i && i.onClick)
            i.onClick()
          else
            router.push(('path' in i && i.path) ? i.path : `/modules/custom-${i.name}`)
        },
      }
    }))

const globalComponents = computed(() =>
    Object
      .entries(client.value?.nuxt?.vueApp._context.components || {})
      .map(([key]) => ({
        pascalName: key,
        global: true,
      } as unknown as Component))
      // filter out lazy components
      .filter(i => !LAZY_COMPONENT_RE.test(i.pascalName))
      // dedupe server components
      .filter(i => !serverComponents.value || [].some((s: any) => s.pascalName === i.pascalName)))

onMounted(() => {
  const disconnect = connectToEmbedApp(iframe.value!, (app) => {
    (async () => {
      const data = await rpc.getServerData()
      const json = `{${Object.entries(data).map(([key, value]) => `"${key}": ${jsonStringifyCircular(value)}`).join(',')}}`
      // @ts-expect-error missing API
      app.uploadData(json)
    })()
    return () => {}
  })

  onUnmounted(() => {
    disconnect()
  })
})

try {
  const branchName = await git('rev-parse', '--abbrev-ref', 'HEAD') || 'head'
  const sha = await git('rev-parse', '--short', 'HEAD')
  const status = await git('status', '--porcelain')
  const isClean = status === ''
  if (isClean)
    return `${branchName}#${sha}`
  return `${branchName}#${sha}-dirty`
}
catch {
  // if the git is not available, fallback to iso string
  return new Date().toISOString().replace(COLON_RE, '-')
}

cache = (() => {
      if (!nitro) {
        return {
          tasks: {},
          scheduledTasks: {},
        }
      }
      return {
        tasks: nitro.options.tasks,
        scheduledTasks: Object.entries(nitro.options.scheduledTasks ?? {})
          .reduce<Record<string, string[]>>((acc, [cron, tasks]) => {
            acc[cron] = Array.isArray(tasks) ? tasks : [tasks]
            return acc
          }, {}),
      }
    })()

if (nuxt.options.dev) {
  nuxt.hook('nitro:init', async (_nitro) => {
    _nitro.options.runtimeConfig.icon ||= {} as any
    Object.defineProperty(_nitro.options.runtimeConfig.icon, 'serverKnownCssClasses', {
      get() {
        return [
          ...options.serverKnownCssClasses || [],
          ...getKnownIconClasses(),
        ]
      },
    })
  })
}

const inlineConfigKeys = new Set(
  await Promise.all([...modulesToInstall].map(async ([mod]) => {
    if (typeof mod === 'string') { return }
    const meta = await Promise.resolve(mod.getMeta?.())
    if (meta?.name) {
      modulesByMetaName.set(meta.name, mod)
    }
    if (meta?.configKey) {
      if (meta.configKey !== meta.name) {
        modulesByMetaName.set(meta.configKey, mod)
      }
      return meta.configKey
    }
  })),
)

for (const key in teleports) {
  const matchClientComp = key.match(SSR_CLIENT_TELEPORT_MARKER)
  if (matchClientComp) {
    const [, uid, clientId] = matchClientComp
    if (!uid || !clientId) { continue }
    templates += `<template data-island-uid="${uid}" data-island-component="${clientId}">${teleports[key]}</template>`
    continue
  }
  const matchSlot = key.match(SSR_SLOT_TELEPORT_MARKER)
  if (matchSlot) {
    const [, uid, slot] = matchSlot
    if (!uid || !slot) { continue }
    templates += `<template data-island-uid="${uid}" data-island-slot="${slot}">${teleports[key]}</template>`
  }
}

addTemplate({
  filename: 'color-mode-options.mjs',
  getContents: () => Object.entries(options).map(([key, value]) =>
    (key === 'storage' ? `/** @type {${Object.values(storageTypes).join(' | ')}} */\n` : '')
    + (key === 'cookieAttrs' ? `/** @type {Record<string, unknown> | undefined} */\n` : '')
    + `export const ${key} = ${JSON.stringify(value, null, 2)}
  `).join('\n'),
})

const versions = [
  { label: `v${config.public.version}`, version: 10, to: "/docs" },
  { label: "v9.5.3", version: 9, to: "https://v9.i18n.nuxtjs.org/docs" },
  {
    label: "v8.5.6",
    version: 8,
    to: "https://v9.i18n.nuxtjs.org/docs/v8/getting-started",
  },
  {
    label: "v7.3.1",
    version: 7,
    to: "https://v9.i18n.nuxtjs.org/docs/v7/setup",
  },
];

for (let i = ctx.vueI18nConfigPaths.length - 1; i >= 0; i--) {
  const config = ctx.vueI18nConfigPaths[i]!
  const identifier = `config_${genSafeVariableName(basename(config.path))}_${config.hash}`
  const key = genString(identifier)

  importStatements.add(genImport(asI18nVirtual(config.hash), identifier))
  vueI18nConfigs.push({
    importer: genDynamicImport(asI18nVirtual(config.hash), { comment: `webpackChunkName: ${key}` }),
    importerServer: `() => Promise.resolve(${identifier})`,
    relative: relative(nuxt.options.buildDir, config.path),
  })
}

addTemplate({
  filename: resolve(nuxt.options.buildDir, './types/i18n-generated-route-types.d.ts'),
  getContents: () => {
    return `// Generated by @nuxtjs/i18n
import type { RouteNamedMapI18n } from 'vue-router/auto-routes'

declare module 'vue-router' {
export interface TypesConfig {
  RouteNamedMapI18n: RouteNamedMapI18n
}
}

export {}`
  },
})

if (Object.prototype.toString.call(evaluated) === '[object Object]') {
  if (evaluated.locales) {
    if (!Array.isArray(evaluated.locales) || evaluated.locales.some(locale => typeof locale !== 'string')) {
      console.warn(`[nuxt-i18n] Invalid locale option used with \`defineI18nRoute\`: ${value}`)
      return
    }
  }
  if (evaluated.paths && Object.prototype.toString.call(evaluated.paths) !== '[object Object]') {
    console.warn(`[nuxt-i18n] Invalid paths option used with \`defineI18nRoute\`: ${value}`)
    return
  }

  return evaluated
}

const _cachedMessageLoader = defineCachedFunction(_messagesHandler, {
  name: 'i18n:messages-internal',
  maxAge: !__I18N_CACHE__ ? -1 : 60 * 60 * 24,
  getKey: event => [getRouterParam(event, 'locale') ?? 'null', getRouterParam(event, 'hash') ?? 'null'].join('-'),
  async shouldBypassCache(event) {
    const locale = getRouterParam(event, 'locale')
    if (locale == null) { return false }
    // prerendering may require initializing context
    const ctx = tryUseI18nContext(event) || await initializeI18nContext(event)
    return !ctx.localeConfigs?.[locale]?.cacheable
  },
})

for (const key in obj) {
  if (!Object.prototype.hasOwnProperty.call(obj, key)) { continue }

  if (isObject(obj[key]) && obj[key] !== null && !isArray(obj[key])) {
    str += `${indent}"${key}": {\n`
    str += generateInterface(obj[key] as Record<string, unknown>, indentLevel + 1)
    str += `${indent}};\n`
  } else {
    let propertyType = isArray(obj[key]) ? 'unknown[]' : typeof obj[key]
    if (isFunction(propertyType)) {
      propertyType = '() => string'
    }
    str += `${indent}"${key}": ${propertyType};\n`
  }
}

for (const locale in localeLoaders) {
  for (let i = 0; i < localeLoaders[locale]!.length; i++) {
    const loader = localeLoaders[locale]![i]!
    statements.push(
      [
        `  import.meta.hot.accept("${loader.relative}", async mod => {`,
        //   replace locale loader
        `    localeLoaders["${locale}"][${i}].load = () => Promise.resolve(mod.default)`,
        //   trigger locale messages reload for locale
        `    await useNuxtApp()._nuxtI18n.dev.resetI18nProperties("${locale}")`,
        `  })`,
      ].join('\n'),
    )
  }
}

if (varDeclarationName) {
  const n = varDeclarations.find(x => x.id.type === 'Identifier' && x.id.name === varDeclarationName.name)
  if (n) {
    if (n.init?.type === 'ObjectExpression') {
      return 'object'
    }

    if (n.init?.type === 'CallExpression' && n.init.callee.type === 'Identifier') {
      const [fnNode] = n.init.arguments
      if (fnNode?.type === 'FunctionExpression' || fnNode?.type === 'ArrowFunctionExpression') {
        return 'function'
      }
    }
  }
}

const refinedSrc = computed(() => {
  if (props.src?.startsWith('/') && !props.src.startsWith('//')) {
    // @ts-expect-error runtime config is not typed
    const _base = withLeadingSlash(withTrailingSlash(useRuntimeConfig().app.baseURL))
    if (_base !== '/' && !props.src.startsWith(_base)) {
      return joinURL(_base, props.src)
    }
  }
  return props.src
})

const [file, { isInNuxt } = {}] = filesImportingTailwind.length === 0
    ? [
        addTemplate({
          filename: 'tailwind.css',
          getContents: () => [`@import ${JSON.stringify(tailwindPath)};`, `@import ${JSON.stringify(sourcesTemplate.dst)};`].join('\n'),
          write: true,
        }).dst,
      ]
    : filesImportingTailwind.find(file => file[1].isInNuxt) || filesImportingTailwind.pop()!

nuxt.hook('builder:watch', (_e, path) => {
  if (path !== file && projectCSSFiles.includes(path)) {
    readFile(file, { encoding: 'utf-8' }).then((fileContents) => {
      if (IMPORT_REGEX.test(fileContents)) {
        logger.withTag('@nuxtjs/tailwindcss').warn(`New import for \`tailwindcss\` detected in ${file}. Restart server.`)
      }
    })
  }
})
